import{_ as o,o as n,c as t,ag as a}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Documentation Conventions","description":"","frontmatter":{},"headers":[],"relativePath":"CONVENTIONS.md","filePath":"CONVENTIONS.md"}'),r={name:"CONVENTIONS.md"};function s(i,e,d,c,h,l){return n(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="documentation-conventions" tabindex="-1">Documentation Conventions <a class="header-anchor" href="#documentation-conventions" aria-label="Permalink to &quot;Documentation Conventions&quot;">​</a></h1><p>This file documents the contracts that the <strong>admin-web</strong> UI relies on when deep-linking to the user guide. Conventions established by <a href="https://teamcentral-ai.atlassian.net/browse/PRD-2423" target="_blank" rel="noreferrer">PRD-2423</a>.</p><h2 id="stable-anchors" tabindex="-1">Stable anchors <a class="header-anchor" href="#stable-anchors" aria-label="Permalink to &quot;Stable anchors&quot;">​</a></h2><p>Anchors referenced from admin-web (via <code>LearnMoreLink</code> and any future tooltip-deep-link components) are part of the user guide&#39;s <strong>API</strong>. They should not be renamed casually.</p><ul><li>Use <strong>kebab-case</strong> slugs: <code>chain-semantics</code>, <code>when-single-found</code>, <code>looping-list-grouped-items</code>.</li><li>No trailing punctuation, no spaces, no quotes.</li><li>Headings drive the anchor — if you rename a heading and the anchor changes, every admin-web consumer needs an update.</li></ul><p>Anchors that need to remain stable are listed in <code>src/components/common/learn-more-link/docHints.ts</code> in the admin-web codebase. If you intend to rename a heading whose slug is registered there, update the map in the same PR.</p><h2 id="when-you-renamed-something-and-forgot" tabindex="-1">When you renamed something and forgot <a class="header-anchor" href="#when-you-renamed-something-and-forgot" aria-label="Permalink to &quot;When you renamed something and forgot&quot;">​</a></h2><p>Symptom: a &quot;Learn more →&quot; link in admin-web opens to the page but scrolls nowhere (anchor doesn&#39;t exist).</p><p>Fix:</p><ol><li>Restore the old anchor on the page (use the <a href="https://vitepress.dev/guide/markdown#custom-anchors" target="_blank" rel="noreferrer">VitePress <code>#anchor</code> markdown syntax</a> if you want a different visible heading) <strong>or</strong></li><li>Update the corresponding entry in <code>docHints.ts</code> to the new anchor.</li></ol><p>The map is <strong>closed</strong> — <code>LearnMoreLink</code> consumers reference hint IDs that must exist in <code>docHints.ts</code>, so admin-web type-checks catch most of these at build time. The exception is when the <em>anchor</em> changes but the <em>hint ID</em> stays the same: that&#39;s the case this contract is here to prevent.</p><h2 id="where-the-docs-deploy" tabindex="-1">Where the docs deploy <a class="header-anchor" href="#where-the-docs-deploy" aria-label="Permalink to &quot;Where the docs deploy&quot;">​</a></h2><p>The VitePress site under <code>docs/</code> builds and deploys to <code>https://teamcentral.github.io/</code> on every push to <code>main</code> (see <code>.github/workflows/deploy_docs.yml</code>). <code>LearnMoreLink</code> resolves URLs against <code>USER_GUIDE_BASE_URL</code> in admin-web&#39;s <code>src/utils/constants.ts</code>, which points at that host.</p><h2 id="adding-a-new-learn-more-affordance" tabindex="-1">Adding a new &quot;Learn more&quot; affordance <a class="header-anchor" href="#adding-a-new-learn-more-affordance" aria-label="Permalink to &quot;Adding a new &quot;Learn more&quot; affordance&quot;">​</a></h2><p>See admin-web&#39;s <code>src/components/common/learn-more-link/README.md</code> for the three-step recipe.</p>',15)])])}const p=o(r,[["render",s]]);export{u as __pageData,p as default};
